const express = require('express');
const fs = require('fs');
const path = require('path');
const cheerio = require('cheerio');
require('dotenv').config();

const app = express();
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

const DB = path.join(__dirname, 'data', 'tenders.json');
function readDB() { try { return JSON.parse(fs.readFileSync(DB,'utf8')); } catch { return {tenders:[]}; } }
function writeDB(data) { fs.writeFileSync(DB, JSON.stringify(data,null,2)); }

app.get('/api/tenders', (req, res) => res.json(readDB()));
app.post('/api/tenders', (req, res) => {
  const db = readDB();
  const t = { ...req.body, id: Date.now(), added: new Date().toLocaleDateString('en-ZA',{day:'numeric',month:'short'}) };
  db.tenders.push(t); writeDB(db); res.json(t);
});
app.patch('/api/tenders/:id', (req, res) => {
  const db = readDB();
  const i = db.tenders.findIndex(t => String(t.id) === req.params.id);
  if (i === -1) return res.status(404).json({error:'Not found'});
  db.tenders[i] = {...db.tenders[i], ...req.body}; writeDB(db); res.json(db.tenders[i]);
});
app.delete('/api/tenders/:id', (req, res) => {
  const db = readDB();
  db.tenders = db.tenders.filter(t => String(t.id) !== req.params.id);
  writeDB(db); res.json({ok:true});
});

// ── eTenders live scraper ─────────────────────────────────────
// Category IDs from etenders.gov.za:
// 29 = Financial and insurance activities
// 30 = Insurance, reinsurance and pension funding
// 4  = Computer programming, consultancy
// 58 = Information and communication
// Province IDs: 5=EC, 7=FS, 8=GP, 9=KZN, 10=LP, 11=MP, 12=NC, 13=NW, 14=WC

const PROVINCE_IDS = { 'Eastern Cape':'5','Free State':'7','Limpopo':'10','Mpumalanga':'11','Northern Cape':'12','North West':'13' };
const CATEGORY_IDS = {
  'insurance': ['29','30'],
  'technology': ['4','58'],
  'all': ['29','30','4','58']
};

app.get('/api/etenders/search', async (req, res) => {
  const keyword = req.query.q || '';
  const page = parseInt(req.query.page || 1);
  const pageSize = 100;
  const start = (page - 1) * pageSize;

  // Target categories from etenders.gov.za
  const INS_CATS = [
    'Financial and insurance activities',
    'Insurance, reinsurance and pension funding, except compulsory social security',
    'Activities auxiliary to financial service and insurance activities.'
  ];
  const TECH_CATS = [
    'Computer programming, consultancy and related activities',
    'Information and communication',
    'Information service activities',
    'Telecommunications'
  ];
  const ALL_CATS = [...INS_CATS, ...TECH_CATS];

  // Build form body for DataTables server-side request
  const params = new URLSearchParams();
  params.append('draw', '1');
  params.append('start', String(start));
  params.append('length', String(pageSize));
  params.append('status', '1'); // Currently advertised
  ALL_CATS.forEach(c => params.append('category[]', c));
  if (keyword) params.append('search[value]', keyword);

  try {
    console.log('Fetching from etenders TenderFilter...');
    const r = await fetch('https://www.etenders.gov.za/Home/TenderFilter/', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Accept': 'application/json',
        'User-Agent': 'Mozilla/5.0',
        'X-Requested-With': 'XMLHttpRequest'
      },
      body: params.toString(),
      signal: AbortSignal.timeout(30000)
    });

    if (!r.ok) throw new Error(`TenderFilter API ${r.status}`);
    const data = await r.json();
    console.log('Response keys:', Object.keys(data));

    // DataTables server-side response: { draw, recordsTotal, recordsFiltered, data: [...] }
    const rows = data.data || data || [];

    const tenders = (Array.isArray(rows) ? rows : []).map(t => {
      const cat = (t.category || '').toLowerCase();
      const isIns = INS_CATS.some(c => c.toLowerCase().includes(cat.split(' ')[0])) || cat.includes('insur') || cat.includes('financial');
      const isTech = TECH_CATS.some(c => c.toLowerCase().includes(cat.split(' ')[0])) || cat.includes('computer') || cat.includes('information') || cat.includes('telecom');
      return {
        ocid: t.tender_No || t.id || String(Math.random()),
        name: t.description || t.tender_No || 'Untitled',
        ref: t.tender_No || '',
        entity: t.department || 'Unknown',
        category: t.category || 'General',
        value: 0,
        deadline: t.closing_Date ? t.closing_Date.split('T')[0] : '',
        province: t.province || 'National',
        sector: isIns ? 'Insurance' : isTech ? 'Tech' : 'Other',
        status: 'evaluating',
        source: 'etenders',
        compulsoryBriefing: t.briefingCompulsory || false,
        briefingDate: t.compulsory_briefing_session || '',
        briefingVenue: t.briefingVenue || '',
        eSubmission: t.eSubmission || false,
        tenderType: t.type || ''
      };
    });

    res.json({ tenders, total: data.recordsTotal || tenders.length, page });
  } catch (err) {
    console.error('TenderFilter error:', err.message);
    // Fallback to OCDS API
    try {
      const dateFrom = '2025-01-01';
      const dateTo = new Date().toISOString().split('T')[0];
      const url = `https://ocds-api.etenders.gov.za/api/OCDSReleases?PageNumber=${page}&PageSize=50&dateFrom=${dateFrom}&dateTo=${dateTo}${keyword ? '&keyword=' + encodeURIComponent(keyword) : ''}`;
      const r2 = await fetch(url, { signal: AbortSignal.timeout(20000) });
      const data2 = await r2.json();
      const releases = data2.releases || [];
      const tenders2 = releases.filter(rel => rel.tender).map(rel => {
        const t = rel.tender;
        return {
          ocid: rel.ocid,
          name: t.description || t.title || 'Untitled',
          ref: t.title || '',
          entity: t.procuringEntity?.name || rel.buyer?.name || 'Unknown',
          category: t.mainProcurementCategory || 'General',
          value: Math.round(t.value?.amount || 0),
          deadline: (t.tenderPeriod?.endDate || '').split('T')[0],
          province: t.province || extractProvince(t.procuringEntity?.name || ''),
          sector: mapSector(t.mainProcurementCategory || '', t.description || ''),
          status: 'evaluating',
          source: 'etenders',
          compulsoryBriefing: t.briefingSession?.compulsory || false,
          briefingDate: t.briefingSession?.date || '',
          briefingVenue: t.briefingSession?.venue || ''
        };
      }).filter(t => t.sector !== 'Other');
      res.json({ tenders: tenders2, total: tenders2.length, page, source: 'ocds' });
    } catch(e2) {
      res.status(500).json({ error: err.message });
    }
  }
});

function extractProvince(name) {
  const n = (name||'').toLowerCase();
  // Direct province names
  if (n.includes('gauteng')) return 'Gauteng';
  if (n.includes('kwazulu') || n.includes('kzn')) return 'KwaZulu-Natal';
  if (n.includes('western cape')) return 'Western Cape';
  if (n.includes('eastern cape')) return 'Eastern Cape';
  if (n.includes('limpopo')) return 'Limpopo';
  if (n.includes('mpumalanga')) return 'Mpumalanga';
  if (n.includes('northern cape')) return 'Northern Cape';
  if (n.includes('north west') || n.includes('northwest')) return 'North West';
  if (n.includes('free state') || n.includes('freestate')) return 'Free State';
  // Municipality to province mapping
  if (n.includes('sekhukhune') || n.includes('vhembe') || n.includes('mopani') || n.includes('waterberg') || n.includes('capricorn')) return 'Limpopo';
  if (n.includes('ehlanzeni') || n.includes('nkangala') || n.includes('gert sibande')) return 'Mpumalanga';
  if (n.includes('john taolo') || n.includes('namakwa') || n.includes('pixley') || n.includes('zf mgcawu') || n.includes('frances baard') || n.includes('sol plaatje') || n.includes('gamagara') || n.includes('tsantsabane')) return 'Northern Cape';
  if (n.includes('or tambo') || n.includes('alfred nzo') || n.includes('joe gqabi') || n.includes('amathole') || n.includes('chris hani') || n.includes('sarah baartman') || n.includes('buffalo city')) return 'Eastern Cape';
  if (n.includes('lejweleputswa') || n.includes('fezile dabi') || n.includes('thabo mofutsanyana') || n.includes('xhariep') || n.includes('mangaung') || n.includes('matjhabeng') || n.includes('tswelopele') || n.includes('tokologo')) return 'Free State';
  if (n.includes('rustenburg') || n.includes('rlm') || n.includes('bojanala') || n.includes('ngaka') || n.includes('dr ruth') || n.includes('kenneth')) return 'North West';
  if (n.includes('eThekwini') || n.includes('ethekwini') || n.includes('umgungundlovu') || n.includes('ugu') || n.includes('ilembe') || n.includes('king cetshwayo') || n.includes('harry gwala') || n.includes('amajuba') || n.includes('zululand')) return 'KwaZulu-Natal';
  return 'National';
}
function guessProvince(text) {
  const p = ['Eastern Cape','Free State','Limpopo','Mpumalanga','Northern Cape','North West','KwaZulu-Natal','Western Cape','Gauteng'];
  return p.find(x => text.includes(x)) || 'National';
}
function mapSector(cat, name) {
  const both = ((cat||'')+(name||'')).toLowerCase();
  if (both.includes('insur')||both.includes('gap cover')||both.includes('broker')||both.includes('financial')) return 'Insurance';
  if (both.includes('train')||both.includes('edu')||both.includes('capacity')) return 'Training';
  if (both.includes('construct')||both.includes('infra')||both.includes('civil')) return 'Construction';
  if (both.includes('tech')||both.includes('software')||both.includes('ict')||both.includes('digital')||both.includes('system')||both.includes('computer')||both.includes('information')) return 'Tech';
  return 'Other';
}

// ── Agent John ────────────────────────────────────────────────
app.post('/api/agent-john', async (req, res) => {
  const key = process.env.ANTHROPIC_API_KEY;
  if (!key) return res.status(500).json({error:'No API key'});
  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method:'POST',
      headers:{'Content-Type':'application/json','x-api-key':key,'anthropic-version':'2023-06-01'},
      body:JSON.stringify({model:'claude-sonnet-4-6',max_tokens:900,system:'You are Agent John, TenderSafe AI bid strategist for South African government tenders. Direct, sharp, specific. Respond with **VERDICT**, **KEY RISKS**, **POSITIONING MOVES**, **NEXT 48 HOURS** sections.',messages:req.body.messages}),
      signal:AbortSignal.timeout(30000)
    });
    const data = await r.json();
    console.log('Anthropic:', JSON.stringify(data).slice(0,200));
    res.json(data);
  } catch(err) {
    console.error('Agent John:', err.message);
    res.status(500).json({error:err.message});
  }
});

app.listen(process.env.PORT||3000, () => console.log(`\n  TenderSafe is running\n  → http://localhost:${process.env.PORT||3000}\n`));
